INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (1,N'El Líder y Pionero',N'Ser un faro de inspiración, liderando con valentía y autenticidad. Aprender a confiar en ti mismo y ser independiente.',N'Superar el miedo al fracaso y confiar en tu intuición para tomar decisiones.',N'“Confío en mi poder interior para crear mi camino único.”',N'Un cristal de cuarzo rojo o un dije en forma de estrella.',N'Eres el inicio del cambio. El universo te ha elegido para abrir nuevas puertas.',1),
	 (2,N'El Mediador y Pacificador',N'Crear armonía en las relaciones y ser un puente entre personas y emociones. Tu empatía es tu mayor fortaleza.',N'Aprender a priorizarte y evitar que otros abusen de tu bondad.',N'“Encuentro la paz en mí y la comparto con el mundo.”',N'Una piedra de luna o una pluma blanca.',N'Eres la conexión entre lo visible y lo invisible, tejiendo hilos de amor y comprensión.',1),
	 (3,N'El Comunicador y Artista',N'Inspirar alegría y creatividad en los demás a través de tu arte o palabras.',N'Mantener el enfoque y superar la procrastinación.',N'“Mi creatividad fluye y transforma mi realidad.”',N'Un colibrí o un cristal citrino.',N'Tus palabras y acciones tienen el poder de sanar corazones y encender almas.',1),
	 (4,N'El Constructor y Organizador',N'Establecer estructuras sólidas y trabajar con disciplina para construir un legado duradero.',N'Aceptar los cambios inesperados con flexibilidad.',N'“Construyo con propósito, creando un futuro sólido y lleno de luz.”',N'Una pirámide pequeña o un ónix negro.',N'Eres el arquitecto del orden divino, creando equilibrio en un mundo caótico.',1),
	 (5,N'El Explorador y Aventurero',N'Explorar lo desconocido, buscar la libertad y enseñar a otros a adaptarse al cambio.',N'Encontrar estabilidad sin sacrificar tu deseo de aventura.',N'“Abrazo el cambio como el motor de mi evolución.”',N'Una brújula antigua o un ágata azul.',N'El universo se mueve contigo. Eres la chispa que ilumina nuevos horizontes.',1),
	 (6,N'El Cuidador y Sanador',N'Servir con amor, creando un espacio seguro para los demás.',N'Aprender a no sacrificarte en exceso por otros.',N'“Mi amor nutre y equilibra el mundo que me rodea.”',N'Un corazón de cuarzo rosa o un dije en forma de flor.',N'Tu energía amorosa sana las heridas del alma. Eres un canal de paz y armonía.',1),
	 (7,N'El Buscador y Filósofo',N'Descubrir los misterios del universo y conectar con la sabiduría interior.',N'Mantener el equilibrio entre el aislamiento y la conexión con los demás.',N'“Exploro el universo dentro de mí para entender el mundo que me rodea.”',N'Un ojo turco o una amatista.',N'Tu mente es un portal hacia lo divino. Eres el buscador de verdades eternas.',1),
	 (8,N'El Poderoso y Visionario',N'Alcanzar el éxito material con integridad y usarlo para un bien mayor.',N'Evitar la ambición desmedida o el apego excesivo al poder.',N'“El éxito fluye hacia mí porque lo uso para iluminar al mundo.”',N'Un lingote pequeño de oro simbólico o un cristal de pirita.',N'El universo confía en ti para manejar el poder con sabiduría y amor.',1),
	 (9,N'El Humanitario y Sabio',N'Servir al mundo con compasión y enseñar a otros a través de tu sabiduría.',N'Soltar el pasado y aceptar los ciclos naturales de la vida.',N'“Sirvo al mundo con amor, compartiendo mi sabiduría eterna.”',N'Un símbolo de infinito o un jaspe rojo.',N'Eres la luz que guía a otros hacia su propósito más elevado.',1),
	 (11,N'El Visionario Espiritual',N'Elevar la consciencia colectiva a través de la intuición y la inspiración espiritual.',N'Equilibrar la gran sensibilidad con el mundo material.',N'“Soy un canal divino de inspiración y luz.”',N'Una estrella de seis puntas o un cristal angelita.',N'Tu visión trasciende lo físico, eres un puente hacia lo divino.',1);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (22,N'El Maestro Constructor',N'Convertir visiones espirituales en proyectos materiales que beneficien a la humanidad.',N'Manejar la presión de grandes responsabilidades.',N'“Manifiesto grandes sueños en realidades tangibles.”',N'Una figura de mandala o un cuarzo transparente.',N'Tus manos tienen el poder de construir el nuevo mundo.',1),
	 (33,N'El Maestro Sanador',N'Sanar a través del amor puro y la protección de los más vulnerables.',N'Evitar el descuido propio por cuidar a los demás.',N'“Mi amor incondicional transforma el mundo.”',N'Una vela blanca o un cuarzo verde.',N'Eres el refugio del amor crístico en la tierra.',1),
	 (44,N'El Maestro del Poder Material y Espiritual',N'Organizar el mundo material con una ética espiritual inquebrantable.',N'Mantener la humildad ante el gran poder alcanzado.',N'“Equilibro lo material y espiritual para crear un legado eterno.”',N'Un anillo con forma de espiral o un cristal obsidiana.',N'Eres la autoridad sagrada que manifiesta la abundancia divina.',1),
	 (1,N'Chispa Independiente',N'Tu alma anhela libertad y ser el autor de su historia.',N'Controlar el ego.',N'“Mi voluntad es divina.”',N'Pirita.',N'Tu fuego interior es imparable.',2),
	 (2,N'Alma Compañera',N'Buscas paz profunda, unión y vínculos reales.',N'Decir no sin culpa.',N'“Amo con equilibrio.”',N'Selenita.',N'Eres el bálsamo del mundo.',2),
	 (3,N'Alma Expresiva',N'Tu esencia se nutre de la risa y el arte.',N'Evitar la dispersión.',N'“Expreso mi verdad.”',N'Citrino.',N'Tu risa es medicina pura.',2),
	 (4,N'El Alma Estable',N'Anhelas seguridad, raíces fuertes y ver resultados tangibles de tus esfuerzos constantes.',N'Soltar la rigidez mental y el miedo a la escasez o al cambio.',N'“Soy tierra firme y mi hogar interior es seguro.”',N'Turmalina Negra o un cubo de madera.',N'Eres la base sólida sobre la que se construyen los grandes sueños.',2),
	 (5,N'El Alma Libre',N'Tu espíritu pide aventura, viajes y cambios constantes. Tu alma odia las ataduras.',N'Aprender a comprometerte sin sentir que pierdes tus alas.',N'“Fluyo con los cambios y crezco en libertad.”',N'Piedra Aguamarina o una pequeña llave.',N'El viento siempre sopla a tu favor para llevarte a nuevas fronteras.',2),
	 (6,N'El Alma Protectora',N'Tu plenitud viene de cuidar, embellecer y dar amor a tu familia o comunidad.',N'Dejar de cargar problemas ajenos que no te corresponden solucionar.',N'“Cuido de mí tanto como cuido de los que amo.”',N'Esmeralda o un dije de Árbol de la Vida.',N'Eres el refugio seguro donde el amor siempre florece.',2),
	 (7,N'Alma Mística',N'Deseas conocimiento oculto y silencio sagrado.',N'No aislarte de la realidad.',N'“La verdad reside en mí.”',N'Labradorita.',N'Eres un canal con lo divino.',2);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (8,N'El Alma Abundante',N'Buscas la maestría sobre el mundo material y el equilibrio perfecto del dar y recibir.',N'Entender que la verdadera riqueza es un estado interno del ser.',N'“Merezco prosperidad y la comparto con sabiduría.”',N'Ojo de Tigre o una moneda antigua.',N'Tienes el poder de manifestar el cielo en la tierra.',2),
	 (9,N'Alma Universal',N'Amor incondicional y cierre de ciclos.',N'Soltar apegos pasados.',N'“Amo sin condiciones.”',N'Lapislázuli.',N'Tu alma es luz antigua.',2),
	 (11,N'El Alma Iluminada',N'Tu esencia anhela despertar conciencias y vivir desde una intuición radical.',N'Superar la hipersensibilidad y el nerviosismo extremo.',N'“Soy un puente entre el cielo y la tierra.”',N'Un cristal de Angelita o Selenita.',N'Tu alma vibra en una frecuencia superior; confía en tus visiones.',2),
	 (22,N'El Alma Constructora',N'Deseas dejar un legado tangible que transforme la realidad de muchos.',N'No dejarte aplastar por la magnitud de tus propios sueños.',N'“Construyo el cielo en la tierra con mis manos.”',N'Un cuarzo ahumado o una piedra tectita.',N'Tu ambición es sagrada porque busca el bienestar colectivo.',2),
	 (33,N'El Alma Crística',N'Tu motor es el amor incondicional y la protección de la vida en todas sus formas.',N'Evitar el martirio o el descuido total de tus propias necesidades.',N'“Mi amor es un escudo de luz para el mundo.”',N'Una esmeralda o un dije de paloma.',N'Has venido a enseñar el poder del perdón y la compasión infinita.',2),
	 (44,N'El Alma de Jerarquía',N'Anhelas el dominio total de las leyes materiales bajo una ética espiritual inquebrantable.',N'No volverte frío o demasiado enfocado en el control.',N'“Manejo el poder con integridad y sabiduría divina.”',N'Un anillo de plata o una turmalina negra.',N'Eres la autoridad espiritual manifestada en el mundo de la materia.',2),
	 (1,N'Liderazgo Soberano',N'Tu destino es convertirte en un pionero independiente, abriendo caminos donde otros no se atreven a entrar. Debes aprender a confiar plenamente en tu visión.',N'Superar la necesidad de aprobación externa y aceptar la soledad que a veces acompaña al líder.',N'“Lidero mi destino con honor y valentía.”',N'Un dije de Sol o una moneda de oro.',N'Naciste para abrir caminos. El universo espera que des el primer paso.',3),
	 (2,N'El Maestro de la Unión',N'Tu destino es dominar el arte de la diplomacia y la cooperación. Estás aquí para unir voluntades y crear paz en entornos divididos.',N'No perderte en las necesidades de los demás y mantener tu centro emocional.',N'“Soy el puente que une y la paz que armoniza.”',N'Un cuarzo blanco o dos hilos entrelazados.',N'Tu fuerza reside en la suavidad. Eres el pegamento que mantiene unido lo sagrado.',3),
	 (3,N'La Expresión Expandida',N'Tu destino es comunicar verdades que inspiren alegría. Debes manifestar tu creatividad en el mundo material para sanar a otros.',N'Enfocar tu talento disperso en una sola gran obra que deje huella.',N'“Mi voz es un canal de luz y creatividad.”',N'Un cristal citrino o una pluma de ave.',N'Viniste a recordarle al mundo que la vida es una celebración divina.',3),
	 (4,N'El Arquitecto del Legado',N'Tu destino es construir algo duradero. Debes manifestar orden, disciplina y bases sólidas para las futuras generaciones.',N'Aprender que la estructura no debe convertirse en una prisión; mantén la mente abierta.',N'“Construyo realidades sólidas con paciencia y fe.”',N'Un ónix negro o una piedra cuadrada.',N'Eres la mano que da forma a la materia. Tu trabajo trasciende el tiempo.',3);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (5,N'Libertad Evolutiva',N'Tu destino es experimentar la vida en todas sus formas. Debes ser un agente de cambio y enseñar a otros a no temer a la incertidumbre.',N'Aprender que la verdadera libertad nace de la disciplina interna, no del libertinaje.',N'“Soy libre en mi evolución y fluyo con el cambio.”',N'Una brújula antigua o un ágata azul.',N'Tu destino es el horizonte. Nunca dejes de explorar lo desconocido.',3),
	 (6,N'La Responsabilidad del Amor',N'Tu destino es alcanzar el ideal del servicio amoroso. Estás aquí para sanar hogares y comunidades a través de la responsabilidad.',N'No intentar arreglar la vida de todos; permite que cada uno aprenda su propia lección.',N'“Sirvo con amor y equilibrio mi entrega.”',N'Un cuarzo rosa o un dije de flor.',N'Eres el corazón del mundo. Donde pones tu intención, florece la vida.',3),
	 (7,N'La Sabiduría del Silencio',N'Tu destino es convertirte en un especialista del espíritu. Debes buscar la verdad detrás de las apariencias y compartir tu conocimiento.',N'Superar el escepticismo y confiar en las señales místicas del universo.',N'“Busco la verdad y la encuentro en mi interior.”',N'Una amatista o un dije de búho.',N'Tu mente es un laboratorio sagrado. Estás aquí para descifrar lo invisible.',3),
	 (8,N'Maestría Material',N'Tu destino es manifestar abundancia y equilibrio de poder. Debes dirigir grandes proyectos con integridad y justicia.',N'Ser justo con el éxito y recordar que el dinero es energía espiritual en movimiento.',N'“Soy abundancia consciente y poder equilibrado.”',N'Una pirita o una moneda antigua.',N'Eres un co-creador de realidades. El poder te ha sido dado para bendecir.',3),
	 (9,N'La Culminación Universal',N'Tu destino es alcanzar la conciencia universal. Estás aquí para cerrar ciclos kármicos y enseñar el amor desinteresado.',N'Soltar los apegos personales por una causa mucho más grande que tú mismo.',N'“Suelto el pasado y me entrego al servicio universal.”',N'Un jaspe rojo o un símbolo de infinito.',N'Tu destino es la luz total. Eres el final de un camino y el inicio de la eternidad.',3),
	 (11,N'El Faro de Conciencia',N'Tu destino es ser un canal de iluminación. Debes actuar como un puente entre dimensiones para despertar a la humanidad.',N'Confiar en tus visiones aunque el mundo no las comprenda aún.',N'“Soy luz en movimiento, guiando el despertar.”',N'Una estrella o un cristal angelita.',N'Tu voz tiene ecos de eternidad. Habla, que el mundo escucha.',3),
	 (22,N'El Visionario Universal',N'Tu destino es materializar utopías. Estás aquí para crear sistemas que cambien la forma en que vive la humanidad.',N'No rendirte ante la magnitud de tus propios sueños.',N'“Construyo el cielo en la tierra con mis manos.”',N'Un cuarzo transparente o un mandala.',N'El arquitecto divino trabaja a través de ti. Manifiesta lo imposible.',3),
	 (33,N'El Avatar del Amor',N'Tu destino es la entrega total y el servicio a la humanidad a través del amor.',N'No descuidar tu propia vida por los demás.',N'“Soy amor en acción.”',N'Cuarzo Verde.',N'Eres un canal de sanación universal.',3),
	 (44,N'El Estratega Divino',N'Manifestar grandes estructuras que unan lo material con lo espiritual.',N'La carga de la responsabilidad masiva.',N'“Materializo la luz.”',N'Obsidiana dorada.',N'Tu legado será eterno y sólido.',3),
	 (1,N'Imagen Magnética',N'El mundo te percibe como una persona segura, audaz y con una gran fuerza de voluntad. Proyectas la imagen de alguien que sabe exactamente a dónde va.',N'Cuidar de no parecer alguien arrogante, frío o demasiado dominante ante los demás.',N'“Mi presencia es poderosa y mi luz abre caminos.”',N'Un Rubí o una piedra de Granate.',N'Tu imagen abre puertas que otros creen cerradas. Confía en tu impacto.',4);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (2,N'Imagen Diplomática',N'Te ven como una persona pacífica, amable y una excelente colaboradora. Proyectas una energía de apoyo y discreción que invita a la confianza.',N'Superar la timidez excesiva y no permitir que tu presencia pase desapercibida por miedo a molestar.',N'“Mi suavidad es mi mayor fortaleza y escudo.”',N'Una Perla o una piedra de Cuarzo Blanco.',N'La gente busca tu compañía para encontrar calma en medio de la tormenta.',4),
	 (3,N'Imagen Brillante',N'Proyectas entusiasmo, alegría y una gran creatividad. El mundo te ve como alguien sociable, ingenioso y lleno de vida.',N'No caer en la superficialidad o en el uso de la máscara del payaso para ocultar tus tristezas.',N'“Irradio alegría y mi creatividad es contagiosa.”',N'Un Topacio o un dije de sol.',N'Eres el centro de luz en cualquier lugar. Tu brillo natural es un regalo para otros.',4),
	 (4,N'Imagen Respetable',N'Te perciben como una persona seria, trabajadora y sumamente confiable. Proyectas orden, disciplina y respeto por las normas.',N'Evitar parecer alguien demasiado rígido, aburrido o severo con los errores de los demás.',N'“Mi integridad es mi carta de presentación.”',N'Un zafiro azul o una piedra de turmalina.',N'Eres la roca en la que otros se apoyan. Tu estabilidad es tu mayor respeto.',4),
	 (5,N'Imagen Versátil',N'El mundo te ve como alguien magnético, adaptable y amante de la libertad. Proyectas una imagen juvenil, curiosa y aventurera.',N'Controlar la inquietud excesiva y evitar proyectar una imagen de irresponsabilidad o falta de compromiso.',N'“Abrazo el cambio y mi energía fluye libremente.”',N'Un cristal de Ojo de Tigre o una Turquesa.',N'Eres un camaleón espiritual. Tu capacidad de adaptación es tu superpoder social.',4),
	 (6,N'Imagen Armoniosa',N'Te perciben como alguien protector, estético y profundamente hogareño. Proyectas una vibración maternal/paternal y de sanación.',N'No cargar con las culpas ajenas ni volverte esclavo de las necesidades de tu entorno por el qué dirán.',N'“Irradio paz, amor y equilibrio en mi entorno.”',N'Una Esmeralda o un dije de corazón.',N'Eres el refugio de muchos. Tu sola presencia armoniza los espacios que habitas.',4),
	 (7,N'Imagen Distinguida',N'Proyectas un aire de misterio, intelecto y refinamiento. Te ven como alguien sabio, observador y quizás un poco solitario.',N'Aprender a ser más accesible y no parecer alguien distante, crítico o frío con los demás.',N'“Mi sabiduría interna brilla con elegancia.”',N'Una piedra de Amatista o una Labradorita.',N'Tu aura es profunda y enigmática. Eres el buscador que otros admiran en silencio.',4),
	 (8,N'Imagen Exitosa',N'Te ven como una persona con gran autoridad, ambiciosa y con capacidad de mando. Proyectas éxito económico y eficiencia.',N'No utilizar tu imagen para intimidar a otros ni enfocarte únicamente en las apariencias materiales.',N'“El poder y la abundancia se manifiestan en mí.”',N'Un diamante o un cristal de Pirita.',N'Naciste para manejar grandes energías. Tu impacto visual es el de un triunfador.',4),
	 (9,N'Imagen Compasiva',N'Proyectas una imagen de sabiduría, tolerancia y amor universal. Te ven como alguien idealista, generoso y desinteresado.',N'No parecer alguien demasiado ingenuo o que vive fuera de la realidad por estar en las nubes.',N'“Mi amor universal envuelve a todo ser vivo.”',N'Un Lapislázuli o un Ópalo.',N'Eres un faro de esperanza. Tu mirada ve la belleza que otros ignoran.',4),
	 (11,N'Imagen Inspiradora',N'Proyectas una energía eléctrica y visionaria. La gente te ve como alguien que está un paso adelante, casi como un profeta moderno.',N'Manejar la ansiedad que te genera ser observado y no sentirte ''raro'' por tu alta sensibilidad.',N'“Soy un canal de inspiración divina aquí y ahora.”',N'Una piedra de Selenita o un cristal Angelita.',N'Tu imagen es un recordatorio de lo divino para quienes te cruzan en el camino.',4),
	 (22,N'El Arquitecto del Mundo',N'Proyectas una capacidad inmensa para materializar sueños a gran escala.',N'No caer en el materialismo puro u olvidar el descanso.',N'“Construyo con sabiduría para el bien común.”',N'Un cubo de pirita o algo de cuarzo rutilado.',N'Tu sola presencia transmite que lo imposible es realizable.',4);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (33,N'La Imagen de la Entrega',N'Proyectas una calidez y un sacrificio que inspira devoción y confianza ciega.',N'No dejar que otros se vuelvan dependientes de tu luz.',N'“Mi servicio es mi mayor brillo.”',N'Un dije de coral o una turquesa.',N'Eres la representación del amor incondicional en la tierra.',4),
	 (44,N'La Imagen de la Estructura Sagrada',N'Proyectas una autoridad implacable unida a una ética espiritual de acero.',N'Parecer una figura demasiado rígida o difícil de alcanzar.',N'“Ordeno el mundo con la justicia del espíritu.”',N'Un anillo de hierro o una obsidiana arcoíris.',N'Transmites la fuerza de los antiguos constructores de templos.',4),
	 (1,N'Año de Inicios',N'Es el momento de sembrar las semillas de lo que quieres cosechar en los próximos 9 años. Debes tomar la iniciativa y confiar en tus nuevos proyectos.',N'Vencer la duda, la procrastinación y el miedo a emprender algo totalmente nuevo.',N'“Hoy comienza mi nueva vida y el universo respalda cada uno de mis pasos.”',N'Ruda o un cristal de Citrino.',N'Es tu año de renacer. Tienes el lienzo en blanco para escribir una nueva historia.',5),
	 (2,N'Año de Gestación',N'Aprender a esperar con paciencia. Es un tiempo para colaborar, fortalecer alianzas y permitir que lo sembrado en el año 1 eche raíces.',N'Controlar la ansiedad por ver resultados rápidos y trabajar en la diplomacia.',N'“Fluyo con el tiempo perfecto de la naturaleza y cultivo mi paz.”',N'Piedra de Luna o una cinta blanca.',N'La magia sucede en el silencio y la cooperación. Escucha tu intuición.',5),
	 (3,N'Año de Expansión',N'Expresar tu creatividad y disfrutar de la vida social. Es un año para brillar, comunicar tus ideas y encontrar alegría en lo cotidiano.',N'No dispersar tu energía en demasiadas cosas y evitar el gasto innecesario.',N'“Mi alegría se expande y atrae bendiciones a mi vida.”',N'Un dije de colibrí o un cristal de Pirita.',N'El universo celebra contigo. Tu entusiasmo es la llave de tu abundancia.',5),
	 (4,N'Año de Construcción',N'Trabajar con disciplina y poner orden en tu vida material y salud. Es tiempo de establecer bases sólidas y realistas.',N'Superar la sensación de pesadez o restricción y evitar la terquedad.',N'“Con cada acción disciplinada, construyo mi libertad futura.”',N'Una piedra de Ónix o un objeto de madera.',N'Eres el arquitecto de tu realidad. El esfuerzo de hoy es la paz de mañana.',5),
	 (5,N'Año de Cambios',N'Adaptarte a lo inesperado y buscar la libertad. Es un año de viajes, movimiento y nuevas experiencias que desafían tu rutina.',N'No caer en excesos o impulsividad que pongan en riesgo tu estabilidad.',N'“Abrazo la aventura del cambio y confío en mi adaptabilidad.”',N'Una brújula o un cristal de Ágata azul.',N'El viento del cambio sopla a tu favor. Atrévete a ser diferente.',5),
	 (6,N'Año del Hogar',N'Enfocarte en la familia, las responsabilidades afectivas y la armonía del entorno. Es un tiempo para sanar vínculos.',N'No asumir cargas familiares que no te corresponden por un sentido de sacrificio.',N'“Mi hogar es un santuario de amor y yo soy su guardián.”',N'Cuarzo rosa o una vela de color rosa.',N'El amor es la fuerza que lo ordena todo. Nutre tu corazón.',5),
	 (7,N'Año de Reflexión',N'Hacer una pausa para el autoconocimiento, el estudio y la espiritualidad. Es un año de introspección profunda.',N'Evitar el aislamiento melancólico o la tendencia a sobreanalizar todo.',N'“Busco la sabiduría en mi interior y encuentro todas las respuestas.”',N'Amatista o un dije de búho.',N'Estás en un retiro espiritual personal. Tu mente se está preparando para la cima.',5),
	 (8,N'Año de Poder',N'Manifestar tus ambiciones y manejar el éxito material. Es el año de la justicia kármica: recibes lo que has trabajado.',N'Mantener el equilibrio entre la ambición y la ética espiritual.',N'“Soy un imán para la prosperidad y el éxito equilibrado.”',N'Una moneda de la suerte o una piedra de Ojo de Tigre.',N'Naciste para mandar y manifestar. El poder es una herramienta sagrada en tus manos.',5);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (9,N'Año de Cierre',N'Limpiar, soltar, perdonar y agradecer. Es el final de un ciclo de 9 años; debes dejar ir lo que ya no vibra contigo.',N'Vencer la resistencia a soltar personas, objetos o situaciones del pasado.',N'“Suelto el pasado con amor, confío en el presente y agradezco lo vivido.”',N'Sal de mar o una pluma blanca.',N'Cierras un gran ciclo hoy. Vacía tus manos para que el universo las llene de nuevo mañana.',5),
	 (1,N'Año Global de Despertar',N'Es el inicio de un ciclo de 9 años para la humanidad. Representa un despertar masivo, nuevas tecnologías y el nacimiento de ideologías que cambiarán el mundo.',N'Adaptarse a la rapidez de los cambios y soltar las estructuras obsoletas del pasado.',N'“Somos uno en el inicio de una nueva era de luz.”',N'Cuarzo Cristal o una punta de cuarzo transparente.',N'El mundo renace contigo. Tu chispa individual es parte del gran incendio del despertar.',6),
	 (2,N'Año Global de Alianzas',N'Un tiempo para la diplomacia mundial, la búsqueda de la paz y el fortalecimiento de las relaciones internacionales y colectivas.',N'Superar la polarización y aprender a trabajar en equipo por el bien común.',N'“En la unión encontramos la fuerza para sanar el planeta.”',N'Piedra de Luna o una cinta de color azul cielo.',N'La cooperación es la clave del milagro. Juntos somos el puente hacia lo nuevo.',6),
	 (3,N'Año Global de Expresión',N'Un periodo de gran creatividad colectiva, avances en la comunicación y una expansión de las artes y la alegría social.',N'Evitar la superficialidad y el uso de la comunicación para desinformar.',N'“La voz del mundo canta una melodía de esperanza.”',N'Citrino o un dije de sol radiante.',N'La alegría es un acto de rebeldía espiritual. Brilla con el mundo.',6),
	 (4,N'Año Global de Estabilidad',N'Tiempo de poner orden en la economía mundial, construir nuevas bases legales y enfocarse en la ecología y el trabajo duro.',N'No caer en la rigidez extrema o en sistemas totalitarios por miedo al caos.',N'“Construimos sobre roca firme el futuro de la humanidad.”',N'Ónix negro o un puñado de tierra sagrada.',N'El orden divino se manifiesta en la tierra. Eres parte del cimiento.',6),
	 (5,N'Año Global de Transformación',N'Un año de revoluciones, descubrimientos científicos asombrosos y una gran necesidad de libertad colectiva.',N'Manejar la inestabilidad social y los cambios repentinos con sabiduría.',N'“La libertad es el motor que mueve nuestra evolución universal.”',N'Ágata azul o una pequeña brújula de bolsillo.',N'El universo acelera su marcha. Siente el viento del cambio en tu rostro.',6),
	 (6,N'Año Global de Responsabilidad',N'Fomento del cuidado comunitario, la educación, la salud pública y el bienestar de los sectores más vulnerables.',N'Equilibrar el servicio social sin caer en el control excesivo de la privacidad.',N'“El amor y la justicia son la ley que rige nuestra unión.”',N'Cuarzo rosa o un símbolo de flor de la vida.',N'La humanidad es una sola familia. Tu servicio es el latido de este corazón.',6),
	 (7,N'Año Global de Espiritualidad',N'Un tiempo de introspección para el planeta, descubrimientos en el espacio y un interés masivo por lo místico y científico.',N'Evitar el fanatismo y buscar la verdad basada en el conocimiento y la fe equilibrada.',N'“La sabiduría del universo se revela a quienes saben escuchar.”',N'Amatista o un cristal de Labradorita.',N'El cielo toca la tierra este año. Escucha los susurros de lo divino.',6),
	 (8,N'Año Global de Cosecha',N'Justicia kármica a nivel mundial. Reequilibrio de la riqueza, el poder y las instituciones financieras.',N'Superar la ambición desmedida y usar el poder para el beneficio de todos.',N'“La abundancia del universo es infinita y equitativa.”',N'Pirita o una moneda de plata.',N'El poder se entrega a quienes saben servir. Es el año de la gran manifestación.',6),
	 (9,N'Año Global de Cierre',N'Final de un ciclo de 9 años. Tiempo de perdonar deudas históricas, soltar viejos paradigmas y prepararse para el renacimiento.',N'No resistirse a los finales necesarios que la humanidad debe atravesar.',N'“Soltamos lo viejo con gratitud y nos preparamos para la luz.”',N'Sal de mar o un incienso de copal.',N'La noche es más oscura justo antes del amanecer. Confía en el final del ciclo.',6);
INSERT INTO guia.dbo.Significados (ValorNumero,Apodo,Mision,Reto,Mantra,Amuleto,MensajeMagico,TemaId) VALUES
	 (1,N'Día de Inicios',N'Hoy la energía te impulsa a tomar la iniciativa. Es un excelente día para comenzar un proyecto, hacer una llamada importante o decidir un cambio personal. La fuerza del ''1'' te da valentía.',N'Vencer la indecisión y no esperar a que otros den el primer paso por ti.',N'“Hoy soy el arquitecto de mi realidad y avanzo con determinación.”',N'Un objeto de color rojo o una piedra Jaspe.',N'El universo te da luz verde hoy. Confía en tu primer impulso.',7),
	 (2,N'Día de Cooperación',N'Hoy es un día para escuchar, colaborar y trabajar en equipo. La energía favorece las alianzas, las reconciliaciones y los detalles sutiles.',N'No tomarte las críticas de forma personal y mantener tu equilibrio emocional.',N'“Fluyo en armonía con los demás y escucho mi voz interior.”',N'Cuarzo blanco o algo de color plata.',N'La magia hoy está en los detalles y en la unión. Sé paciente.',7),
	 (3,N'Día de Expresión',N'La energía de hoy es expansiva y alegre. Es el momento ideal para comunicar tus ideas, escribir, crear arte o simplemente disfrutar de una buena charla.',N'Evitar la dispersión y no gastar energía en chismes o quejas innecesarias.',N'“Mi palabra crea belleza y mi alegría es contagiosa.”',N'Citrino o algo de color amarillo/oro.',N'Tu sonrisa es tu mejor talismán hoy. Comparte tu brillo.',7),
	 (4,N'Día de Orden',N'Hoy toca poner los pies en la tierra. Organiza tu agenda, limpia tu espacio o termina esas tareas pendientes que requieren disciplina.',N'No dejarte ganar por el cansancio o la sensación de rutina pesada.',N'“Organizo mi mundo y construyo bases sólidas para mis sueños.”',N'Ónix o algo de color café/verde oscuro.',N'La disciplina de hoy es la libertad de mañana. Construye con fe.',7),
	 (5,N'Día de Aventura',N'Hoy el universo te pide movimiento. Rompe la rutina, prueba algo nuevo o haz un viaje corto. La energía es rápida y llena de sorpresas.',N'Controlar la impulsividad y no tomar decisiones permanentes basadas en emociones temporales.',N'“Abrazo lo inesperado y aprendo de cada nueva experiencia.”',N'Aguamarina o algo de color azul turquesa.',N'El cambio es la única constante. ¡Diviértete explorando hoy!',7),
	 (6,N'Día del Corazón',N'Hoy la prioridad es el hogar y los seres queridos. Dedica tiempo a sanar vínculos, embellecer tu casa o dar un consejo amoroso.',N'Evitar querer controlar la vida de los demás bajo la excusa de cuidarlos.',N'“Doy y recibo amor en equilibrio perfecto.”',N'Cuarzo rosa o algo de color rosa/verde.',N'Donde pones tu amor hoy, nace un milagro. Cuida tu santuario.',7),
	 (7,N'Día de Introspección',N'Un día para el silencio y el estudio. Busca un momento para meditar, leer o investigar un tema profundo. Tu intuición está al máximo.',N'No caer en pensamientos melancólicos o aislarte por miedo al mundo.',N'“En el silencio encuentro las respuestas que buscaba.”',N'Amatista o algo de color violeta.',N'Hay un mensaje oculto para ti hoy. Escucha con el alma.',7),
	 (8,N'Día de Manifestación',N'La energía favorece los negocios, el dinero y el poder personal. Es un buen día para negociar o concretar temas materiales importantes.',N'Actuar con total integridad; recuerda que lo que das hoy, vuelve multiplicado.',N'“Soy un canal de abundancia y manejo mi poder con sabiduría.”',N'Pirita o algo de color cobre/bronce.',N'Eres un imán para la prosperidad. Proyecta tu éxito.',7),
	 (9,N'Día de Cierre',N'Hoy es para soltar. Termina lo que empezaste, perdona, limpia tus cajones y prepárate para un nuevo ciclo. Momento de altruismo.',N'No aferrarte a lo que ya cumplió su función en tu vida.',N'“Suelto con amor y agradezco todo lo aprendido hoy.”',N'Lapislázuli o algo de color blanco puro.',N'Estás liberando espacio para lo grande que viene. Confía.',7);
